      ...(payload.options.trunk && { trunk: payload.options.trunk }),
    }).pipe(
      Effect.mapError(
        (e: PreflightError) =>
          new ExecutorPreflightError({
            context: {
              check: e.context.check,
              detail: e.message,
            },
          }),
      ),
    )
